const created: any = await firstValueFrom(this.trackingService.createSample(result));
// Optimistic insert: show the new row immediately so we don't depend on a
// read-after-write re-query (which can race the backend and miss the row).
if (created && created.sample_id_pk != null) {
  const [decorated] = this.decorateSampleRows([created]);
  const id = created.sample_id_pk;
